"""Apply the reviewed IMP-057 State Package portability patch."""

from __future__ import annotations

import base64
import subprocess
import zlib

_PATCH = ""


def main() -> int:
    patch = zlib.decompress(base64.b64decode(_PATCH))
    subprocess.run(
        ["git", "apply", "--whitespace=nowarn", "-"],
        input=patch,
        check=True,
    )
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
